//! gemma4-pipeline-smoke — runs the WHOLE Gemma3/4 inference pipeline
//! end-to-end as a single native binary against a local `.knot` file.
//!
//! Mirrors `native-pipeline-smoke.rs` (the Qwen2 reference smoke) but
//! drives `model_gemma4::Gemma4Pipeline` instead. Used to validate the
//! Gemma kernel math + per-layer hooks (post_attn_norm, post_ffw_norm,
//! layer_output_scale, partial-RoPE, GeGLU, tanh logit softcap, sliding-
//! vs-global attention dispatch) without round-tripping through the
//! 11-service Cloud Run mesh or the 180-tri-split CF Workers.
//!
//! Usage:
//!   cargo run --release --bin gemma4-pipeline-smoke -- \
//!     /tmp/gemma4-31b-it.knot \
//!     --tokens 2,7166,4099,16517,1564,7140,236881
//!
//!   cargo run --release --bin gemma4-pipeline-smoke -- \
//!     --rknot /tmp/gemma4-31b-it.rknot \
//!     --dense /tmp/gemma4-31b-it.knot \
//!     --tokens 2,7166,4099,16517,1564,7140,236881
//!
//! The token IDs above encode "<bos>What is the capital of France?" in
//! Gemma's sentencepiece (verify against your tokenizer; IDs differ
//! across model versions). Expected first-decode-token: " The" or "Paris"
//! depending on how the chat template wraps the prompt.

use std::env;
use std::path::Path;
use std::sync::Arc;
use std::time::Instant;

use distributed_inference::loader::{KnotWeights, WeightBackend};
use distributed_inference::model_gemma4::Gemma4Pipeline;
use distributed_inference::rknot::rknot_backend::RknotBackend;

#[derive(Debug)]
struct Args {
    dense_path: String,
    rknot_path: Option<String>,
    token_ids: Vec<u32>,
    per_token: bool,
}

fn usage(program: &str) -> String {
    format!(
        "usage: {program} <knot-path> --tokens <id1,id2,...>\n       \
         {program} --rknot <path.rknot> --dense <path.knot> --tokens <id1,id2,...>"
    )
}

fn parse_args() -> Result<Args, String> {
    let raw: Vec<String> = env::args().collect();
    let program = raw
        .first()
        .map(|s| s.as_str())
        .unwrap_or("gemma4-pipeline-smoke");

    let mut dense_path: Option<String> = None;
    let mut rknot_path: Option<String> = None;
    let mut tokens: Option<String> = None;
    let mut positional: Option<String> = None;
    let mut per_token = false;

    let mut i = 1usize;
    while i < raw.len() {
        match raw[i].as_str() {
            "--dense" => {
                i += 1;
                dense_path = Some(
                    raw.get(i)
                        .ok_or_else(|| "--dense needs a path".to_string())?
                        .clone(),
                );
            }
            "--rknot" => {
                i += 1;
                rknot_path = Some(
                    raw.get(i)
                        .ok_or_else(|| "--rknot needs a path".to_string())?
                        .clone(),
                );
            }
            "--tokens" => {
                i += 1;
                tokens = Some(
                    raw.get(i)
                        .ok_or_else(|| "--tokens needs a comma-separated list".to_string())?
                        .clone(),
                );
            }
            "--per-token" => {
                // Drive the production /generate path: per-token
                // `forward_one(token, pos)` for the full prompt, then read
                // `get_logits()`. Validates the incremental KV/RoPE decode
                // against the batched prefill (the default mode here).
                per_token = true;
            }
            "-h" | "--help" => return Err(usage(program)),
            arg if arg.starts_with('-') => {
                return Err(format!("unknown arg: {arg}\n{}", usage(program)))
            }
            path => {
                if positional.is_some() {
                    return Err(format!(
                        "unexpected positional arg: {path}\n{}",
                        usage(program)
                    ));
                }
                positional = Some(path.to_string());
            }
        }
        i += 1;
    }

    let dense_path = dense_path.or(positional).ok_or_else(|| usage(program))?;
    let token_ids = tokens
        .ok_or_else(|| usage(program))?
        .split(',')
        .map(|s| {
            s.trim()
                .parse::<u32>()
                .map_err(|e| format!("bad token {:?}: {}", s, e))
        })
        .collect::<Result<Vec<_>, _>>()?;
    if token_ids.is_empty() {
        return Err("--tokens parsed to an empty list".to_string());
    }

    Ok(Args {
        dense_path,
        rknot_path,
        token_ids,
        per_token,
    })
}

fn main() -> Result<(), String> {
    let args = parse_args()?;

    let t0 = Instant::now();
    println!("============================================================");
    println!(" gemma4-pipeline-smoke");
    println!("   dense  : {}", args.dense_path);
    if let Some(rknot_path) = args.rknot_path.as_deref() {
        println!("   rknot  : {}", rknot_path);
    }
    println!("   tokens : {:?}", args.token_ids);
    println!("============================================================");

    println!("[1/6] load knot");
    let t = Instant::now();
    let dense_knot =
        KnotWeights::load(&args.dense_path).map_err(|e| format!("dense knot load: {:?}", e))?;
    let knot = if let Some(rknot_path) = args.rknot_path.as_deref() {
        let dense_backend: Arc<dyn WeightBackend> = Arc::clone(&dense_knot.backend);
        let rknot_backend = RknotBackend::open(Path::new(rknot_path))
            .map_err(|e| format!("rknot open: {:?}", e))?
            .with_dense_fallback(dense_backend);
        println!(
            "       rknot spectral tensors={}",
            rknot_backend.tensor_count()
        );
        KnotWeights::from_rknot(rknot_backend, dense_knot)
    } else {
        dense_knot
    };
    let cfg_summary = match &knot.config {
        Some(c) => format!(
            "arch={} hidden={} layers={} heads={} kv={} head_dim={} ffn={} vocab={} \
             rope_theta={} sw_pat={:?} sw={:?} g_hd={:?} g_kv={:?} qpas={:?} cap={:?} prf={:?} rsf={:?}",
            c.arch, c.hidden_dim, c.num_layers, c.num_heads, c.num_kv_heads,
            c.head_dim, c.intermediate_size, c.vocab_size, c.rope_theta,
            c.sliding_window_pattern, c.sliding_window, c.global_head_dim,
            c.global_num_kv_heads, c.query_pre_attn_scalar, c.final_logit_softcap,
            c.rope_partial_factor, c.rope_scaling_factor,
        ),
        None => "(none — Gemma4 needs config)".to_string(),
    };
    println!(
        "       ok ({} ms)  config={}",
        t.elapsed().as_millis(),
        cfg_summary
    );

    println!("[2/6] Gemma4Pipeline::from_knot");
    let t = Instant::now();
    let mut pipeline = Gemma4Pipeline::from_knot(knot)?;
    println!("       ok ({} ms)", t.elapsed().as_millis());

    let seq_len = args.token_ids.len();
    let hidden_dim = pipeline.config.hidden_dim;
    let num_layers = pipeline.config.num_layers;

    // ── PER-TOKEN MODE ──────────────────────────────────────────────────
    // Drive `forward_one(token, pos)` for every prompt token in sequence —
    // identical to fat-station's /generate prefill loop — then read
    // `get_logits()`. This is the EXACT production serving path; comparing
    // its top token against the default batched-prefill top token validates
    // the incremental KV/RoPE decode.
    if args.per_token {
        println!(
            "[per-token] forward_one prefill over {} tokens (mirrors /generate)",
            seq_len
        );
        let t = Instant::now();
        for (pos, &tok) in args.token_ids.iter().enumerate() {
            pipeline.forward_one(tok, pos)?;
        }
        let logits = pipeline.get_logits().to_vec();
        let lo = logits.iter().cloned().fold(f32::INFINITY, f32::min);
        let hi = logits.iter().cloned().fold(f32::NEG_INFINITY, f32::max);
        println!(
            "       ok ({} ms)  vocab={}  range=[{:.3}, {:.3}]",
            t.elapsed().as_millis(),
            logits.len(),
            lo,
            hi
        );
        let mut idx: Vec<usize> = (0..logits.len()).collect();
        idx.sort_by(|&a, &b| {
            logits[b]
                .partial_cmp(&logits[a])
                .unwrap_or(std::cmp::Ordering::Equal)
        });
        println!("       top-10 (per-token forward_one):");
        for &i in idx.iter().take(10) {
            println!("         id={:6}  logit={:.4}", i, logits[i]);
        }
        println!(
            "\n[done] per-token forward_one ran. wall={} ms",
            t0.elapsed().as_millis()
        );
        return Ok(());
    }

    println!("[3/6] embed lookup (manual: token_embd_weight rows → residual)");
    // The kernel doesn't expose an `embed_chunk` for Gemma4 yet (the qwen
    // path has one but we keep this binary minimal). Stand up a tiny
    // dequant-and-gather: read token_embd_weight as Q4_K rows and copy
    // each token's row into the residual buffer.
    //
    // Gemma 3/4 multiplies token embeddings by sqrt(hidden_dim) on
    // input — the standard Gemma "embed scaling" trick.  Without it
    // the residual stream starts ~73× too small for gemma4-31B
    // (sqrt(5376)=73.32) and the LayerNorm denominator dominates
    // attention-output noise → garbage logits.  This is documented in
    // `docs/GEMMA4_31B_DEPLOYMENT_STATUS.md` § "lm_head tied-embedding
    // scaling" and matches HF `Gemma4Model.forward`:
    //     `hidden_states = inputs_embeds * sqrt(self.config.hidden_size)`
    // The DEPLOYED Aether path applies this in the coordinator before
    // streaming to the layer mesh — so when wiring this kernel into a
    // CF Workers cobordism deploy the scale should land in the cobordism
    // merge step, NOT here. This smoke is standalone so we apply inline.
    let t = Instant::now();
    use distributed_inference::math::{
        dequantize_q4k_row, dequantize_q5_0_row, dequantize_q5k_row, dequantize_q6k_row,
        dequantize_q8_0_row,
    };
    use distributed_inference::model::{bytes_to_f32_slice, dequantize_f16_row, QType};
    let embed_ref = &pipeline.locs.embed;
    let embed_qtype = embed_ref.qtype;
    println!(
        "       embed tensor={} qtype={:?}",
        embed_ref.name, embed_qtype
    );
    let embed_bytes = pipeline
        .knot
        .backend
        .fetch_tensor(&embed_ref.name)
        .map_err(|e| format!("fetch token_embd_weight: {:?}", e))?;
    let embed_scale = (hidden_dim as f32).sqrt();
    let mut residual = vec![0.0f32; seq_len * hidden_dim];
    let mut row_buf = vec![0.0f32; hidden_dim];
    for (i, tid) in args.token_ids.iter().enumerate() {
        let tok = *tid as usize;
        match embed_qtype {
            QType::F32 => {
                let emb = bytes_to_f32_slice(&embed_bytes);
                let start = tok * hidden_dim;
                row_buf.copy_from_slice(&emb[start..start + hidden_dim]);
            }
            QType::F16 => dequantize_f16_row(&mut row_buf, &embed_bytes, tok, hidden_dim),
            QType::Q4K => dequantize_q4k_row(&mut row_buf, &embed_bytes, tok, hidden_dim),
            QType::Q5_0 => dequantize_q5_0_row(&mut row_buf, &embed_bytes, tok, hidden_dim),
            QType::Q5K => dequantize_q5k_row(&mut row_buf, &embed_bytes, tok, hidden_dim),
            QType::Q6K => dequantize_q6k_row(&mut row_buf, &embed_bytes, tok, hidden_dim),
            QType::Q8_0 => dequantize_q8_0_row(&mut row_buf, &embed_bytes, tok, hidden_dim),
        }
        for j in 0..hidden_dim {
            row_buf[j] *= embed_scale;
        }
        residual[i * hidden_dim..(i + 1) * hidden_dim].copy_from_slice(&row_buf);
    }
    drop(embed_bytes);
    let emb_min = residual.iter().cloned().fold(f32::INFINITY, f32::min);
    let emb_max = residual.iter().cloned().fold(f32::NEG_INFINITY, f32::max);
    println!(
        "       ok ({} ms)  range=[{:.4}, {:.4}]",
        t.elapsed().as_millis(),
        emb_min,
        emb_max
    );

    println!("[4/6] forward all {} layers", num_layers);
    let mut last_layer_out: Vec<f32> = residual.clone();
    let mut total_ms: u128 = 0;
    for layer in 0..num_layers {
        let is_first = layer == 0;
        let is_last = layer == num_layers - 1;
        let lt = Instant::now();
        let attn_input: &[f32] = if is_first { &residual[..] } else { &[] };
        pipeline.forward_range_attn_chunk(attn_input, layer, 0, seq_len, is_first)?;
        pipeline.forward_range_ffn_gate_chunk(layer, seq_len)?;
        pipeline.forward_range_ffn_up_chunk(layer, seq_len)?;
        let out = pipeline.forward_range_ffn_down_chunk(layer, seq_len, is_last)?;
        let lms = lt.elapsed().as_millis();
        total_ms += lms;
        if is_last {
            last_layer_out = out;
        }

        // Per-layer last-token stats — same shape as native-pipeline-smoke
        // so existing diff harnesses can compare side-by-side.
        let last_off = (seq_len - 1) * hidden_dim;
        let last_tok = pipeline.get_residual(seq_len);
        let last_tok = &last_tok[last_off..last_off + hidden_dim];
        let max = last_tok.iter().fold(0.0f32, |a, &b| a.max(b.abs()));
        let mean = last_tok.iter().map(|&v| v.abs()).sum::<f32>() / hidden_dim as f32;
        let sum_sq: f32 = last_tok.iter().map(|&v| v * v).sum();
        let rms = (sum_sq / hidden_dim as f32).sqrt();
        let kind = if pipeline.is_global_layer(layer) {
            "G"
        } else {
            "S"
        };
        if true {
            println!(
                "       L{:>2}/{} [{}] {:>4} ms  max={:.3} mean={:.3} rms={:.3}",
                layer, num_layers, kind, lms, max, mean, rms
            );
        }
    }
    println!(
        "       ok  total={} ms  avg/layer={:.1} ms",
        total_ms,
        total_ms as f64 / num_layers as f64
    );

    println!("[5/6] lm_head_only");
    let t = Instant::now();
    let logits = pipeline.lm_head_only(&last_layer_out, seq_len)?;
    let lo = logits.iter().cloned().fold(f32::INFINITY, f32::min);
    let hi = logits.iter().cloned().fold(f32::NEG_INFINITY, f32::max);
    println!(
        "       ok ({} ms)  vocab={}  range=[{:.3}, {:.3}]",
        t.elapsed().as_millis(),
        logits.len(),
        lo,
        hi
    );

    println!("[6/6] argmax + top-10");
    let mut idx: Vec<usize> = (0..logits.len()).collect();
    idx.sort_by(|&a, &b| {
        logits[b]
            .partial_cmp(&logits[a])
            .unwrap_or(std::cmp::Ordering::Equal)
    });
    println!("       top-10:");
    for &i in idx.iter().take(10) {
        println!("         id={:6}  logit={:.4}", i, logits[i]);
    }

    let total = t0.elapsed().as_millis();
    println!("\n[done] gemma4 pipeline ran end-to-end. wall={} ms", total);
    Ok(())
}
